     1	#version 440
     2	
     3	layout(location = 0) in vec2 qt_TexCoord0;
     4	layout(location = 0) out vec4 fragColor;
     5	
     6	layout(std140, binding = 0) uniform buf {
     7	    mat4 qt_Matrix;
     8	    float qt_Opacity;
     9	    vec2 itemSize;
    10	    float phase;
    11	};
    12	
    13	const float PI = 3.14159265358979323846;
    14	const float OUTER_RADIUS = 18.0;
    15	const float BORDER_WIDTH = 2.0;
    16	const float TRAIL_LENGTH = 0.5;
    17	const vec3 TRAIL_COLOR = vec3(1.0, 0.2, 0.8);
    18	
    19	float roundedRectSdf(vec2 point, vec2 size, float radius)
    20	{
    21	    vec2 halfSize = size * 0.5;
    22	    vec2 q = abs(point - halfSize) - (halfSize - vec2(radius));
    23	    return length(max(q, vec2(0.0))) + min(max(q.x, q.y), 0.0) - radius;
    24	}
    25	
    26	float roundedRectPosition(vec2 point, vec2 size, float radius)
    27	{
    28	    float horizontal = max(0.0, size.x - radius * 2.0);
    29	    float vertical = max(0.0, size.y - radius * 2.0);
    30	    float arc = PI * radius * 0.5;
    31	    float perimeter = max(1.0,
    32	        horizontal * 2.0 + vertical * 2.0 + arc * 4.0);
    33	    float right = size.x - radius;
    34	    float bottom = size.y - radius;
    35	    float distance = 0.0;
    36	
    37	    if (point.y <= radius) {
    38	        if (point.x < radius) {
    39	            float angle = atan(point.y - radius, point.x - radius);
    40	            if (angle < 0.0)
    41	                angle += PI * 2.0;
    42	            distance = horizontal * 2.0 + vertical * 2.0 + arc * 3.0
    43	                + (angle - PI) * radius;
    44	        } else if (point.x > right) {
    45	            float angle = atan(point.y - radius, point.x - right);
    46	            distance = horizontal + (angle + PI * 0.5) * radius;
    47	        } else {
    48	            distance = point.x - radius;
    49	        }
    50	    } else if (point.y >= bottom) {
    51	        if (point.x > right) {
    52	            float angle = atan(point.y - bottom, point.x - right);
    53	            distance = horizontal + vertical + arc + angle * radius;
    54	        } else if (point.x < radius) {
    55	            float angle = atan(point.y - bottom, point.x - radius);
    56	            distance = horizontal * 2.0 + vertical + arc * 2.0
    57	                + (angle - PI * 0.5) * radius;
    58	        } else {
    59	            distance = horizontal + vertical + arc * 2.0
    60	                + (right - point.x);
    61	        }
    62	    } else if (point.x >= right) {
    63	        distance = horizontal + arc + (point.y - radius);
    64	    } else if (point.x <= radius) {
    65	        distance = horizontal * 2.0 + vertical + arc * 3.0
    66	            + (bottom - point.y);
    67	    }
    68	
    69	    return fract(distance / perimeter);
    70	}
    71	
    72	void main()
    73	{
    74	    vec2 size = max(itemSize, vec2(1.0));
    75	    vec2 point = qt_TexCoord0 * size;
    76	    float radius = min(OUTER_RADIUS, min(size.x, size.y) * 0.5);
    77	    float sdf = roundedRectSdf(point, size, radius);
    78	    float halfBorder = BORDER_WIDTH * 0.5;
    79	    float antialias = max(fwidth(sdf), 0.35);
    80	    float borderAlpha = 1.0 - smoothstep(
    81	        halfBorder - antialias,
    82	        halfBorder + antialias,
    83	        abs(sdf + halfBorder)
    84	    );
    85	
    86	    float centerInset = halfBorder;
    87	    vec2 centerSize = max(vec2(1.0),
    88	        size - vec2(centerInset * 2.0));
    89	    float centerRadius = max(0.001, radius - centerInset);
    90	    float position = roundedRectPosition(
    91	        point - vec2(centerInset), centerSize, centerRadius);
    92	    float behindHead = fract(phase - position);
    93	    float trailAlpha = behindHead <= TRAIL_LENGTH
    94	        ? pow(1.0 - behindHead / TRAIL_LENGTH, 1.35)
    95	        : 0.0;
    96	
    97	    float alpha = borderAlpha * trailAlpha * qt_Opacity;
    98	    fragColor = vec4(TRAIL_COLOR * alpha, alpha);
    99	}

